// Channel Normalizer - Supports Webhook, WhatsApp Trigger, Gmail Trigger
const input = $json;

let channel = 'web';
let query = '';
let userEmail = null;
let userPhone = null;
let userHandle = null;
let senderName = null;

// 1. WHATSAPP TRIGGER
if (input.messages && Array.isArray(input.messages) && input.messages.length > 0) {
  channel = 'whatsapp';
  const message = input.messages[0];
  const contact = input.contacts && input.contacts.length > 0 ? input.contacts[0] : null;
  if (message.text && message.text.body) {
    query = message.text.body;
  } else if (message.text) {
    query = typeof message.text === 'string' ? message.text : JSON.stringify(message.text);
  }
  userPhone = message.from || contact?.wa_id || null;
  senderName = contact?.profile?.name || null;
  userHandle = message.from_user_id || null;
}
// 2. WEBHOOK
else if (input.body && typeof input.body === 'object') {
  channel = input.body.channel || 'web';
  query = input.body.query || input.body.text || '';
  userEmail = input.body.user_email || input.body.email || null;
  userPhone = input.body.user_phone || input.body.phone || null;
  userHandle = input.body.user_handle || input.body.handle || null;
  senderName = input.body.sender_name || null;
}
// 3. GMAIL TRIGGER
else if (input.From || input.Subject || input.snippet || input.payload) {
  channel = 'email';
  let fromRaw = input.From || input.from || '';
  if (fromRaw) {
    const emailMatch = fromRaw.match(/<([^>]+)>/);
    if (emailMatch) {
      userEmail = emailMatch[1];
      const nameMatch = fromRaw.match(/^([^<]+)/);
      if (nameMatch) {
        senderName = nameMatch[1].trim();
      }
    } else {
      userEmail = fromRaw.trim();
      senderName = fromRaw.trim();
    }
  }
  query = input.snippet || input.text || input.body || input.html || '';
  if (!query && input.Subject) query = input.Subject;
  if (input.html && !input.text && !input.body) {
    query = input.html.replace(/<[^>]*>/g, '').trim();
  }
  if (!query && input.payload) {
    try {
      if (input.payload.parts) {
        for (const part of input.payload.parts) {
          if (part.body && part.body.data) {
            const decoded = Buffer.from(part.body.data, 'base64').toString('utf-8');
            if (decoded) {
              query = decoded.replace(/<[^>]*>/g, '').trim();
              break;
            }
          }
        }
      }
    } catch (e) {}
  }
}
// 4. FALLBACK
else {
  query = input.query || input.text || input.message || input.Body || input.body || input.snippet || '';
  channel = input.channel || 'unknown';
  userEmail = input.user_email || input.email || input.from || input.From || null;
  userPhone = input.user_phone || input.phone || input.From || null;
  userHandle = input.user_handle || input.handle || input.sender || null;
  senderName = input.sender_name || input.name || input.From || null;
}

if (typeof query === 'string') {
  query = query.trim();
} else {
  query = String(query || '').trim();
}
if (!query && input.Subject) query = input.Subject;
if (userEmail && userEmail.includes('<')) {
  const match = userEmail.match(/<([^>]+)>/);
  if (match) userEmail = match[1];
}
return {
  query: query,
  channel: channel,
  user_email: userEmail,
  user_phone: userPhone,
  user_handle: userHandle,
  sender_name: senderName,
  timestamp: new Date().toISOString(),
  raw: input
};

// Parse Classification
let content = {};
try {
  content = typeof $json.text === 'string' ? JSON.parse($json.text) : ($json.intent ? $json : {});
} catch (e) {
  content = {};
}
const normalizerData = $('Channel Normalizer').item.json;
return {
  query: normalizerData.query || $json.query,
  user_email: normalizerData.user_email || $json.user_email,
  user_phone: normalizerData.user_phone || null,
  user_handle: normalizerData.user_handle || null,
  sender_name: normalizerData.sender_name || null,
  channel: normalizerData.channel || 'web',
  intent: content.intent || 'general',
  entities: content.entities || {},
  confidence: content.confidence || 50
};

