return {
  response: "I'm not confident I understood your question correctly. I'm connecting you with a human agent who will help you shortly. You'll hear from us within a short while.",
  query: $('Parse Classification').first().json.query,
  intent: $('Parse Classification').first().json.intent,
  confidence: $('Parse Classification').first().json.confidence,
  channel: $('Parse Classification').first().json.channel,
  user_email: $('Parse Classification').first().json.user_email,
  user_phone: $('Parse Classification').first().json.user_phone,
  escalated: true,
  timestamp: new Date().toISOString()
};

// Store Author ID from whichever branch succeeded
// Check all three author lookup branches
let authorId = null;
let authorData = null;
let authorName = null;
let authorEmail = null;

// Check Get Author by Email
try {
  const emailAuthor = $('Get Author by Email').item.json;
  if (emailAuthor) {
    if (Array.isArray(emailAuthor) && emailAuthor.length > 0) {
      authorData = emailAuthor[0];
    } else if (typeof emailAuthor === 'object' && emailAuthor.id) {
      authorData = emailAuthor;
    }
  }
} catch (e) {}

// If no author, check Get Author by Phone
if (!authorData) {
  try {
    const phoneAuthor = $('Get Author by Phone').item.json;
    if (phoneAuthor) {
      if (Array.isArray(phoneAuthor) && phoneAuthor.length > 0) {
        authorData = phoneAuthor[0];
      } else if (typeof phoneAuthor === 'object' && phoneAuthor.id) {
        authorData = phoneAuthor;
      }
    }
  } catch (e) {}
}

// If still no author, check Get Author by Email (for Email)
if (!authorData) {
  try {
    const emailAuthor2 = $('Get Author by Email (for Email)').item.json;
    if (emailAuthor2) {
      if (Array.isArray(emailAuthor2) && emailAuthor2.length > 0) {
        authorData = emailAuthor2[0];
      } else if (typeof emailAuthor2 === 'object' && emailAuthor2.id) {
        authorData = emailAuthor2;
      }
    }
  } catch (e) {}
}

// Extract author data
if (authorData) {
  authorId = authorData.id || null;
  authorName = authorData.full_name || null;
  authorEmail = authorData.email || null;
}

// Get Parse Classification data for context
const parseData = $('Parse Classification').item.json;

// Return ALL data needed by downstream nodes
return {
  author_id: authorId,
  author_data: authorData,
  author_name: authorName,
  author_email: authorEmail,
  query: parseData.query || '',
  intent: parseData.intent || 'general',
  confidence: parseData.confidence || 50,
  channel: parseData.channel || 'web',
  user_email: parseData.user_email || null,
  user_phone: parseData.user_phone || null,
  user_handle: parseData.user_handle || null,
  sender_name: parseData.sender_name || null,
  entities: parseData.entities || {},
  author_found: !!authorData
};

