// AGGREGATE BOOKS - SIMPLIFIED
// ============================================

const allItems = $input.all();
let allBooks = [];

if (allItems && allItems.length > 0) {
  for (const item of allItems) {
    const json = item.json;
    if (!json) continue;

    if (json.data && Array.isArray(json.data)) {
      allBooks = allBooks.concat(json.data);
    } else if (Array.isArray(json)) {
      allBooks = allBooks.concat(json);
    } else if (json.id) {
      allBooks.push(json);
    }
  }
}

// Get data from Code in JavaScript - use .item.json
let codeJsData = {};
try {
  const codeJsItem = $('Code in JavaScript');
  if (codeJsItem && codeJsItem.length > 0) {
    codeJsData = codeJsItem[0].json;
  } else if (codeJsItem && codeJsItem.item) {
    codeJsData = codeJsItem.item.json;
  }
} catch (e) {
  console.log('Error reading Code in JavaScript:', e.message);
}

// Return ALL data combined
return {
  // All fields from Code in JavaScript
  query: codeJsData.query || '',
  intent: codeJsData.intent || 'general',
  confidence: codeJsData.confidence || 50,
  channel: codeJsData.channel || 'web',
  user_email: codeJsData.user_email || null,
  user_phone: codeJsData.user_phone || null,
  user_handle: codeJsData.user_handle || null,
  sender_name: codeJsData.sender_name || null,
  entities: codeJsData.entities || {},
  author_data: codeJsData.author_data || null,
  author_name: codeJsData.author_name || null,
  author_email: codeJsData.author_email || null,
  author_id: codeJsData.author_id || null,
  author_found: codeJsData.author_found || false,

  // Books data
  all_books: allBooks,
  total_books: allBooks.length
};

// ============================================
// PREPARE DATA - SIMPLIFIED
// ============================================

// Get ALL data from Aggregate Books (which already has everything)
const data = $('Aggregate Books').item.json;

// Extract data
const allBooks = data.all_books || [];
const authorName = data.author_name || null;
const authorId = data.author_id || null;
const authorData = data.author_data || null;

// Create book list text
let bookListText = '';
if (allBooks.length > 0) {
  bookListText = allBooks.map((b, i) => 
    `${i+1}. "${b.book_title}"${b.book_live_date ? ` ✅ Live (${b.book_live_date})` : ' 🔄 In Progress'}`
  ).join('\n');
}

// Create detailed book information
let bookDetailsText = '';
if (allBooks.length > 0) {
  bookDetailsText = allBooks.map((b, i) => {
    const status = b.book_live_date ? `Live since ${b.book_live_date}` : 'Not yet live';
    const royalty = b.royalty_status || 'Pending';
    const sales = b.sales_count || 0;
    const isbn = b.isbn || 'N/A';
    const addOns = b.add_on_services && b.add_on_services.length > 0 
      ? ` | Add-ons: ${b.add_on_services.join(', ')}` 
      : '';
    return `${i+1}. "${b.book_title}" - ${status} | Royalty: ${royalty} | Sales: ${sales} | ISBN: ${isbn}${addOns}`;
  }).join('\n');
}

// Find specific book from entities
let specificBook = null;
const requestedBookTitle = data.entities?.book_title || null;
if (requestedBookTitle && allBooks.length > 0) {
  specificBook = allBooks.find(b => 
    b.book_title && b.book_title.toLowerCase().includes(requestedBookTitle.toLowerCase())
  );
}

// Return ALL data
return {
  // Query and classification data
  query: data.query || '',
  intent: data.intent || 'general',
  confidence: data.confidence || 50,
  channel: data.channel || 'web',
  user_email: data.user_email || null,
  user_phone: data.user_phone || null,
  user_handle: data.user_handle || null,
  sender_name: data.sender_name || null,
  entities: data.entities || {},

  // Author data
  author_data: authorData,
  author_name: authorName || (allBooks.length > 0 ? 'Author' : null),
  author_email: data.author_email || null,
  author_id: authorId,
  author_found: data.author_found || false,

  // Book data
  book_data: specificBook,
  book_title: specificBook?.book_title || null,
  all_books: allBooks,
  total_books: allBooks.length,
  book_list_text: bookListText,
  book_details_text: bookDetailsText,

  // Debug
  _debug: {
    has_author: !!authorData,
    has_books: allBooks.length > 0,
    total_books: allBooks.length,
    author_id: authorId,
    has_query: !!data.query,
    query_value: data.query || 'empty'
  }
};
